R_MAX, it makes sense to use it for the window size as well.\nmm/vmpressure.c-34- *\nmm/vmpressure.c-35- * TODO: Make the window size depend on machine size, as we do for vmstat\nmm/vmpressure.c-36- * thresholds. Currently we set it to 512 pages (2MB for 4KB pages).\nmm/vmpressure.c-37- */\nmm/vmpressure.c:38:static const unsigned long vmpressure_win = SWAP_CLUSTER_MAX * 16;\nmm/vmpressure.c-39-\nmm/vmpressure.c-40-/*\nmm/vmpressure.c-41- * These thresholds are used when we account memory pressure through\nmm/vmpressure.c-42- * scanned/reclaimed ratio. The current values were chosen empirically. In\nmm/vmpressure.c-43- * essence, they are percents: the higher the value, the more number\nmm/vmpressure.c-44- * unsuccessful reclaims there were.\nmm/vmpressure.c-45- */\nmm/vmpressure.c:46:static const unsigned int vmpressure_level_med = 60;\nmm/vmpressure.c:47:static const unsigned int vmpressure_level_critical = 95;\nmm/vmpressure.c-48-\nmm/vmpressure.c-49-/*\nmm/vmpressure.c:50: * When there are too little pages left to scan, vmpressure() may miss the\nmm/vmpressure.c-51- * critical pressure as number of pages will be less than \"window size\".\nmm/vmpressure.c-52- * However, in that case the vmscan priority will raise fast as the\nmm/vmpressure.c-53- * reclaimer will try to scan LRUs more deeply.\nmm/vmpressure.c-54- *\nmm/vmpressure.c-55- * The vmscan logic considers these special priorities:\nmm/vmpressure.c-56- *\nmm/vmpressure.c-57- * prio == DEF_PRIORITY (12): reclaimer starts with that value\nmm/vmpressure.c-58- * prio <= DEF_PRIORITY - 2 : kswapd becomes somewhat overwhelmed\nmm/vmpressure.c-59- * prio == 0                : close to OOM, kernel scans every page in an lru\nmm/vmpressure.c-60- *\nmm/vmpressure.c-61- * Any value in this range is acceptable for this tunable (i.e. from 12 to\nmm/vmpressure.c:62: * 0). Current value for the vmpressure_level_critical_prio is chosen\nmm/vmpressure.c-63- * empirically, but the number, in essence, means that we consider\nmm/vmpressure.c-64- * critical level when scanning depth is ~10% of the lru size (vmscan\nmm/vmpressure.c-65- * scans 'lru_size >> prio' pages, so it is actually 12.5%, or one\nmm/vmpressure.c-66- * eights).\nmm/vmpressure.c-67- */\nmm/vmpressure.c:68:static const unsigned int vmpressure_level_critical_prio = ilog2(100 / 10);\nmm/vmpressure.c-69-\nmm/vmpressure.c:70:static struct vmpressure *work_to_vmpressure(struct work_struct *work)\nmm/vmpressure.c-71-{\nmm/vmpressure.c:72:\treturn container_of(work, struct vmpressure, work);\nmm/vmpressure.c-73-}\nmm/vmpressure.c-74-\nmm/vmpressure.c:75:static struct vmpressure *vmpressure_parent(struct vmpressure *vmpr)\nmm/vmpressure.c-76-{\nmm/vmpressure.c:77:\tstruct mem_cgroup *memcg = vmpressure_to_memcg(vmpr);\nmm/vmpressure.c-78-\nmm/vmpressure.c-79-\tmemcg = parent_mem_cgroup(memcg);\nmm/vmpressure.c-80-\tif (!memcg)\nmm/vmpressure.c-81-\t\treturn NULL;\nmm/vmpressure.c:82:\treturn memcg_to_vmpressure(memcg);\nmm/vmpressure.c-83-}\nmm/vmpressure.c-84-\nmm/vmpressure.c:85:enum vmpressure_levels {\nmm/vmpressure.c-86-\tVMPRESSURE_LOW = 0,\nmm/vmpressure.c-87-\tVMPRESSURE_MEDIUM,\nmm/vmpressure.c-88-\tVMPRESSURE_CRITICAL,\nmm/vmpressure.c-89-\tVMPRESSURE_NUM_LEVELS,\nmm/vmpressure.c-90-};\nmm/vmpressure.c-91-\nmm/vmpressure.c:92:enum vmpressure_modes {\nmm/vmpressure.c-93-\tVMPRESSURE_NO_PASSTHROUGH = 0,\nmm/vmpressure.c-94-\tVMPRESSURE_HIERARCHY,\nmm/vmpressure.c-95-\tVMPRESSURE_LOCAL,\nmm/vmpressure.c-96-\tVMPRESSURE_NUM_MODES,\nmm/vmpressure.c-97-};\nmm/vmpressure.c-98-\nmm/vmpressure.c:99:static const char * const vmpressure_str_levels[] = {\nmm/vmpressure.c-100-\t[VMPRESSURE_LOW] = \"low\",\nmm/vmpressure.c-101-\t[VMPRESSURE_MEDIUM] = \"medium\",\nmm/vmpressure.c-102-\t[VMPRESSURE_CRITICAL] = \"critical\",\nmm/vmpressure.c-103-};\nmm/vmpressure.c-104-\nmm/vmpressure.c:105:static const char * const vmpressure_str_modes[] = {\nmm/vmpressure.c-106-\t[VMPRESSURE_NO_PASSTHROUGH] = \"default\",\nmm/vmpressure.c-107-\t[VMPRESSURE_HIERARCHY] = \"hierarchy\",\nmm/vmpressure.c-108-\t[VMPRESSURE_LOCAL] = \"local\",\nmm/vmpressure.c-109-};\nmm/vmpressure.c-110-\nmm/vmpressure.c:111:static enum vmpressure_levels vmpressure_level(unsigned long pressure)\nmm/vmpressure.c-112-{\nmm/vmpressure.c:113:\tif (pressure >= vmpressure_level_critical)\nmm/vmpressure.c-114-\t\treturn VMPRESSURE_CRITICAL;\nmm/vmpressure.c:115:\telse if (pressure >= vmpressure_level_med)\nmm/vmpressure.c-116-\t\treturn VMPRESSURE_MEDIUM;\nmm/vmpressure.c-117-\treturn VMPRESSURE_LOW;\nmm/vmpressure.c-118-}\nmm/vmpressure.c-119-\nmm/vmpressure.c:120:static enum vmpressure_levels vmpressure_calc_level(unsigned long scanned,\nmm/vmpressure.c-121-\t\t\t\t\t\t    unsigned long reclaimed)\nmm/vmpressure.c-122-{\nmm/vmpressure.c-123-\tunsigned long scale = scanned + reclaimed;\nmm/vmpressure.c-124-\tunsigned long pressure = 0;\nmm/vmpressure.c-125-\nmm/vmpressure.c-126-\t/*\nmm/vmpressure.c-127-\t * reclaimed can be greater than scanned for things such as reclaimed\nmm/vmpressure.c-128-\t * slab pages. shrink_node() just adds reclaimed pages without a\nmm/vmpressure.c-129-\t * related increment to scanned pages.\nmm/vmpressure.c-130-\t */\n--\nmm/vmpressure.c-137-\t * scanned. This makes it possible to set desired reaction time\nmm/vmpressure.c-138-\t * and serves as a ratelimit.\nmm/vmpressure.c-139-\t */\nmm/vmpressure.c-140-\tpressure = scale - (reclaimed * scale / scanned);\nmm/vmpressure.c-141-\tpressure = pressure * 100 / scale;\nmm/vmpressure.c-142-\nmm/vmpressure.c-143-out:\nmm/vmpressure.c-144-\tpr_debug(\"%s: %3lu  (s: %lu  r: %lu)\\n\", __func__, pressure,\nmm/vmpressure.c-145-\t\t scanned, reclaimed);\nmm/vmpressure.c-146-\nmm/vmpressure.c:147:\treturn vmpressure_level(pressure);\nmm/vmpressure.c-148-}\nmm/vmpressure.c-149-\nmm/vmpressure.c:150:struct vmpressure_event {\nmm/vmpressure.c-151-\tstruct eventfd_ctx *efd;\nmm/vmpressure.c:152:\tenum vmpressure_levels level;\nmm/vmpressure.c:153:\tenum vmpressure_modes mode;\nmm/vmpressure.c-154-\tstruct list_head node;\nmm/vmpressure.c-155-};\nmm/vmpressure.c-156-\nmm/vmpressure.c:157:static bool vmpressure_event(struct vmpressure *vmpr,\nmm/vmpressure.c:158:\t\t\t     const enum vmpressure_levels level,\nmm/vmpressure.c-159-\t\t\t     bool ancestor, bool signalled)\nmm/vmpressure.c-160-{\nmm/vmpressure.c:161:\tstruct vmpressure_event *ev;\nmm/vmpressure.c-162-\tbool ret = false;\nmm/vmpressure.c-163-\nmm/vmpressure.c-164-\tmutex_lock(&vmpr->events_lock);\nmm/vmpressure.c-165-\tlist_for_each_entry(ev, &vmpr->events, node) {\nmm/vmpressure.c-166-\t\tif (ancestor && ev->mode == VMPRESSURE_LOCAL)\nmm/vmpressure.c-167-\t\t\tcontinue;\nmm/vmpressure.c-168-\t\tif (signalled && ev->mode == VMPRESSURE_NO_PASSTHROUGH)\nmm/vmpressure.c-169-\t\t\tcontinue;\nmm/vmpressure.c-170-\t\tif (level < ev->level)\nmm/vmpressure.c-171-\t\t\tcontinue;\nmm/vmpressure.c-172-\t\teventfd_signal(ev->efd);\nmm/vmpressure.c-173-\t\tret = true;\nmm/vmpressure.c-174-\t}\nmm/vmpressure.c-175-\tmutex_unlock(&vmpr->events_lock);\nmm/vmpressure.c-176-\nmm/vmpressure.c-177-\treturn ret;\nmm/vmpressure.c-178-}\nmm/vmpressure.c-179-\nmm/vmpressure.c:180:static void vmpressure_work_fn(struct work_struct *work)\nmm/vmpressure.c-181-{\nmm/vmpressure.c:182:\tstruct vmpressure *vmpr = work_to_vmpressure(work);\nmm/vmpressure.c-183-\tunsigned long scanned;\nmm/vmpressure.c-184-\tunsigned long reclaimed;\nmm/vmpressure.c:185:\tenum vmpressure_levels level;\nmm/vmpressure.c-186-\tbool ancestor = false;\nmm/vmpressure.c-187-\tbool signalled = false;\nmm/vmpressure.c-188-\nmm/vmpressure.c-189-\tspin_lock(&vmpr->sr_lock);\nmm/vmpressure.c-190-\t/*\nmm/vmpressure.c:191:\t * Several contexts might be calling vmpressure(), so it is\nmm/vmpressure.c-192-\t * possible that the work was rescheduled again before the old\nmm/vmpressure.c-193-\t * work context cleared the counters. In that case we will run\nmm/vmpressure.c-194-\t * just after the old work returns, but then scanned might be